import{_ as e,c as a,a2 as i,o as r}from"./chunks/framework.CKjLqgBu.js";const p=JSON.parse('{"title":"Interview Presentation Design: \\"From Builder to Multiplier\\"","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"plans/2026-03-04-interview-presentation-design.md","filePath":"plans/2026-03-04-interview-presentation-design.md","lastUpdated":null}'),n={name:"plans/2026-03-04-interview-presentation-design.md"};function o(d,t,s,l,c,h){return r(),a("div",null,t[0]||(t[0]=[i('<h1 id="interview-presentation-design-from-builder-to-multiplier" tabindex="-1">Interview Presentation Design: &quot;From Builder to Multiplier&quot; <a class="header-anchor" href="#interview-presentation-design-from-builder-to-multiplier" aria-label="Permalink to &quot;Interview Presentation Design: &quot;From Builder to Multiplier&quot;&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>A 20-30 minute Slidev presentation for Staff/Principal Engineer interviews, showcasing 14+ years of career evolution from hands-on IC to organizational force multiplier.</p><h2 id="narrative-structure-the-multiplier-arc" tabindex="-1">Narrative Structure: The Multiplier Arc <a class="header-anchor" href="#narrative-structure-the-multiplier-arc" aria-label="Permalink to &quot;Narrative Structure: The Multiplier Arc&quot;">​</a></h2><p>Chronological career arc in three acts, demonstrating increasing blast radius of impact.</p><h2 id="slide-plan" tabindex="-1">Slide Plan <a class="header-anchor" href="#slide-plan" aria-label="Permalink to &quot;Slide Plan&quot;">​</a></h2><h3 id="opening-1-5-min" tabindex="-1">Opening (1.5 min) <a class="header-anchor" href="#opening-1-5-min" aria-label="Permalink to &quot;Opening (1.5 min)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Slide</th><th>Content</th></tr></thead><tbody><tr><td>1</td><td>Title</td><td>&quot;From Builder to Multiplier: 14 Years of Growing Engineering Impact&quot; -- Name, Staff+ objective, one-liner</td></tr><tr><td>2</td><td>Career Timeline</td><td>Visual timeline: VIVOTEK (2010) -&gt; Mozilla (2012) -&gt; Acadine (2015) -&gt; KaiOS (2016) -&gt; VIVOTEK (2020-present)</td></tr></tbody></table><h3 id="act-1-builder-5-min" tabindex="-1">Act 1: Builder (5 min) <a class="header-anchor" href="#act-1-builder-5-min" aria-label="Permalink to &quot;Act 1: Builder (5 min)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Slide</th><th>Content</th></tr></thead><tbody><tr><td>3</td><td>Firefox OS: Window Management</td><td>Sole designer/implementer of window mgmt for a mobile OS. Architecture diagram. ~600 commits, ~1200 reviews, ~500 bugs.</td></tr><tr><td>4</td><td>KaiOS: React Migration</td><td>Refactored entire OS UI with React/ES6. -20MB memory, -10s boot time.</td></tr><tr><td>5</td><td>Builder Takeaway</td><td>&quot;Deep system-level expertise, shipping under real constraints&quot;</td></tr></tbody></table><h3 id="act-2-architect-7-min" tabindex="-1">Act 2: Architect (7 min) <a class="header-anchor" href="#act-2-architect-7-min" aria-label="Permalink to &quot;Act 2: Architect (7 min)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Slide</th><th>Content</th></tr></thead><tbody><tr><td>6</td><td>Platform Vision</td><td>The problem: 4 product lines (NVR, VORTEX, Reseller Portal, VPP), fragmented codebases</td></tr><tr><td>7</td><td>Monorepo + Microfrontend</td><td>pnpm workspaces unifying 4 products, Module Federation for independent deployments, semantic-release</td></tr><tr><td>8</td><td>VAOM</td><td>4 teams duplicating video analytics visualization -&gt; 1 shared module adopted across all platforms. Later transferred ownership.</td></tr><tr><td>9</td><td>VORTEX OpenAPI + RFC 9457</td><td>Third-party integration via web components (March Networks, DeltaGrid). 235+ error mappings.</td></tr><tr><td>10</td><td>Architect Takeaway</td><td>&quot;Seeing duplication as a system problem, not a team problem&quot;</td></tr></tbody></table><h3 id="act-3-multiplier-10-min" tabindex="-1">Act 3: Multiplier (10 min) <a class="header-anchor" href="#act-3-multiplier-10-min" aria-label="Permalink to &quot;Act 3: Multiplier (10 min)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Slide</th><th>Content</th></tr></thead><tbody><tr><td>11</td><td>API Governance</td><td>ADP framework, 3 training courses, 17+ API groups under migration, roundtable culture</td></tr><tr><td>12</td><td>The AI Shift</td><td>Context: why methodology matters more than tools</td></tr><tr><td>13</td><td>HADLC Methodology</td><td>5-phase diagram: Human-Centric Inception -&gt; Agent-Oriented Inception -&gt; Breakdown -&gt; Construction -&gt; Operations</td></tr><tr><td>14</td><td>E-Map: Proof of Concept</td><td>OpenSpec-driven delivery, live screenshots (web + iOS), shipped product</td></tr><tr><td>15</td><td>Community &amp; Mentoring</td><td>Scaled frontend community 2-&gt;20+, DadaFly mentor, training curricula, cross-department conferences</td></tr></tbody></table><h3 id="close-3-min" tabindex="-1">Close (3 min) <a class="header-anchor" href="#close-3-min" aria-label="Permalink to &quot;Close (3 min)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Slide</th><th>Content</th></tr></thead><tbody><tr><td>16</td><td>Impact Summary</td><td>Key metrics: 14+ years, 3 OSes, 600+ commits (FxOS), 235+ error mappings, 4 products unified, 17+ API groups, community 2-&gt;20+, E-Map shipped via HADLC</td></tr><tr><td>17</td><td>What I Bring</td><td>Vision for Staff+ impact: platform thinking, methodology design, multiplier mindset</td></tr><tr><td>18</td><td>Thank You + Q&amp;A</td><td>Contact info, links (alivedise.dev, speakerdeck, github)</td></tr></tbody></table><p><strong>Total: 18 slides, ~25 minutes</strong></p><h2 id="visual-design" tabindex="-1">Visual Design <a class="header-anchor" href="#visual-design" aria-label="Permalink to &quot;Visual Design&quot;">​</a></h2><ul><li><strong>Tool:</strong> Slidev</li><li><strong>Theme:</strong> <code>seriph</code> (dark background, clean, professional)</li><li><strong>Color coding:</strong> Blue (Act 1: Builder), Teal (Act 2: Architect), Orange (Act 3: Multiplier)</li><li><strong>Diagrams:</strong> Mermaid inline</li><li><strong>Screenshots:</strong> Reuse from existing presentations (E-Map, HADLC)</li><li><strong>Style:</strong> Minimal text per slide, visuals and metrics forward, speaker notes for talking points</li></ul><h2 id="asset-sources" tabindex="-1">Asset Sources <a class="header-anchor" href="#asset-sources" aria-label="Permalink to &quot;Asset Sources&quot;">​</a></h2><ul><li>E-Map screenshots: <code>projects/ai-coding-report-2025/public/images/emap-*.png</code></li><li>HADLC/excalidraw diagrams: <code>presentations/agentic-dev-sharing-rd-managers-20260211/public/hadlc-*.excalidraw</code></li><li>Additional E-Map screenshots: <code>presentations/agentic-dev-sharing-rd-managers-20260211/public/emap-*.png</code></li></ul><h2 id="project-location" tabindex="-1">Project Location <a class="header-anchor" href="#project-location" aria-label="Permalink to &quot;Project Location&quot;">​</a></h2><p><code>presentations/interview-works-introduction/</code></p><h2 id="key-messaging-per-act" tabindex="-1">Key Messaging Per Act <a class="header-anchor" href="#key-messaging-per-act" aria-label="Permalink to &quot;Key Messaging Per Act&quot;">​</a></h2><h3 id="act-1-staff-signal" tabindex="-1">Act 1 -- Staff Signal <a class="header-anchor" href="#act-1-staff-signal" aria-label="Permalink to &quot;Act 1 -- Staff Signal&quot;">​</a></h3><p>Owned a critical OS subsystem end-to-end. Deep technical depth under shipping pressure.</p><h3 id="act-2-staff-signal" tabindex="-1">Act 2 -- Staff Signal <a class="header-anchor" href="#act-2-staff-signal" aria-label="Permalink to &quot;Act 2 -- Staff Signal&quot;">​</a></h3><p>Saw fragmentation across teams as a system problem. Built shared infrastructure (monorepo, VAOM, OpenAPI) that unified 4 product lines. Designed for handoff, not ownership hoarding.</p><h3 id="act-3-staff-signal" tabindex="-1">Act 3 -- Staff Signal <a class="header-anchor" href="#act-3-staff-signal" aria-label="Permalink to &quot;Act 3 -- Staff Signal&quot;">​</a></h3><p>Moved beyond building systems to changing how an organization works. Designed HADLC methodology, proved it with E-Map, established API governance, scaled engineering community. &quot;10x others instead of only 10x yourself.&quot;</p>',30)]))}const m=e(n,[["render",o]]);export{p as __pageData,m as default};
